exercises.solution_code:
#include <iostream>
#include <utility>

int main()
{
    int a{};
    double b{};
    int c{};
    int d{};

    std::cin >> a >> b >> c >> d;

    std::pair pair1{ a, b };
    std::pair pair2{ c, d };
    std::pair pair3{ pair1.first, pair2.first };

    std::cout << pair1.first << ' ' << pair1.second << '\n';
    std::cout << pair2.first << ' ' << pair2.second << '\n';
    std::cout << pair3.first << ' ' << pair3.second << '\n';

    return 0;
}

